"""Records platform data that using HTTP post commands"""
import os
import shutil
try:
    from Tkinter import Label
except ImportError:
    from tkinter import Label
import time
import datetime
import socket
from threading import Thread
import requests
import paramiko
from scp import SCPClient


class HttpRecorder(object):
    """HttpRecorder Class"""

    def __init__(self, name, url_start, url_stop, data_start, data_stop,
                 robot, output_dir, root, ui_queue):
        self.name = name
        self.__url_start = url_start
        self.__url_stop = url_stop
        self.__data_start = data_start
        self.__data_stop = data_stop
        self.__root = root
        self.__ssh_connected = False
        self.__cancel_waiting = False
        self.robot = robot
        self.directory = output_dir + '/' + name
        self.ui_queue = ui_queue
        self.has_started = False
        self.has_stopped = False
        self.label = Label(self.__root)
        self.label.pack()
        self.scp = None
        self.sftp = None
        self.ssh = None
        self.start_response = None
        self.stop_response = None
        self.recording_start_time = None
        self.recording_stop_time = None

    def start(self):
        """Init SSH client"""
        self.update_ui('Starting recorder')

        # Remove previous directory and make new directory
        shutil.rmtree(self.directory, ignore_errors=True)
        os.makedirs(self.directory)

        # Create SSH client
        self.ssh = paramiko.SSHClient()
        self.ssh.load_system_host_keys()
        self.ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())

        # Create ssh connecting thread
        connecting_thread = Thread(target=self.ssh_connect)
        connecting_thread.start()
        # Create waiting for successful connection thread
        waiting_thread = Thread(target=self.ssh_wait)
        waiting_thread.start()

    def ssh_connect(self):
        """SSH connects to the robot"""
        try:
            # SSH connect is a blocking call
            self.ssh.connect(self.robot, 22, 'root', 'jibo')
            # Set to true once a connection is made
            self.__ssh_connected = True
        except paramiko.BadHostKeyException:
            self.update_ui('Server host key could not be verified', 'red')
        except paramiko.AuthenticationException:
            self.update_ui('Authentication failed', 'red')
        except paramiko.SSHException:
            self.update_ui('Unable to establish SSH connection', 'red')
        except socket.error:
            self.update_ui('Socket error occurred while connecting', 'red')

        # Connection has resolve, cancel the waiting thread
        self.__cancel_waiting = True

    def ssh_wait(self):
        """Wait for a connection to be made.  Then send the start message"""
        while not self.__cancel_waiting:
            self.update_ui('Waiting for ssh connection', None, False)
            time.sleep(0.01)

        # Done with waiting.
        if self.__ssh_connected:
            self.update_ui('ssh connected', 'dark green', False)
            self.scp = SCPClient(self.ssh.get_transport())
            self.sftp = self.ssh.open_sftp()
            # Get recording start timestamp
            self.recording_start_time = datetime.datetime.utcnow()
            if self.__url_start is not None:
                # Send start reqest
                self.start_response = requests.post(self.__url_start, self.__data_start)
                # Update UI based on response
                if self.start_response.ok:
                    self.has_started = True
                    self.update_ui('Sent START', 'dark green')
                else:
                    self.has_started = False
                    self.update_ui('Failed START', 'red')

    def stop(self):
        """Send stop request"""
        self.__cancel_waiting = True

        if self.has_started:
            # Get recording stop timestamp
            self.recording_stop_time = datetime.datetime.utcnow()
            self.update_ui('Stopping recorder')
            if self.__url_stop is not None:
                # Send stop post
                self.stop_response = requests.post(self.__url_stop, self.__data_stop)
                # Update UI based on response
                if self.stop_response.ok:
                    self.has_stopped = True
                    self.update_ui('Sent STOP', 'dark green')
                else:
                    self.has_stopped = False
                    self.update_ui('Failed STOP', 'red')
        else:
            self.update_ui('Never started', 'red')

    def exit(self):
        """Exit"""
        self.update_ui('Exiting recorder')
        self.__cancel_waiting = True

        if self.scp is not None:
            self.scp.close()
        if self.sftp is not None:
            self.sftp.close()
        if self.ssh is not None:
            self.ssh.close()

    def update_ui(self, message, color='blue', printout=True):
        """Update GUI and print to console"""
        text = '[' + self.name + '] '+ message
        if printout:
            print(text)
        self.ui_queue.insert(0, {"label":self.label, "text":text, "color":color})
